/**
 * Utilities shared across Panorama360 modules.
 *
 * This file intentionally has no framework dependencies.
 */

import * as THREE from 'three';

export function $(root, selector) {
  const el = (root || document).querySelector(selector);
  if (!el) throw new Error(`Panorama360: missing element for selector: ${selector}`);
  return el;
}

export function isString(v) {
  return typeof v === 'string' || v instanceof String;
}

export function resolveContainer(container) {
  if (!container) throw new Error('Panorama360: options.container is required');
  if (container instanceof HTMLElement) return container;
  if (isString(container)) {
    const el = document.querySelector(container);
    if (!el) throw new Error(`Panorama360: container not found: ${container}`);
    return el;
  }
  throw new Error('Panorama360: container must be an HTMLElement or selector string');
}

export function clamp(v, min, max) {
  return Math.min(max, Math.max(min, v));
}

export function nowMs() {
  return (typeof performance !== 'undefined' && performance.now) ? performance.now() : Date.now();
}

export function parseQueryParams(search = window.location.search) {
  const params = new URLSearchParams(search || '');
  const out = {};
  for (const [k, v] of params.entries()) out[k] = v;
  return out;
}

/**
 * Convert latitude/longitude to a vector on a sphere surface.
 * Assumes lat/lon in degrees, following common pano conventions:
 * - lat: [-90..90] (up/down)
 * - lon: [-180..180] (left/right)
 */
export function latLonToVector3(latDeg, lonDeg, radius = 500) {
  const lat = THREE.MathUtils.degToRad(latDeg);
  const lon = THREE.MathUtils.degToRad(lonDeg);

  // Y-up coordinate system; lon rotates around Y, lat around X.
  const x = radius * Math.cos(lat) * Math.sin(lon);
  const y = radius * Math.sin(lat);
  const z = -radius * Math.cos(lat) * Math.cos(lon);
  return new THREE.Vector3(x, y, z);
}

/**
 * Inverse of latLonToVector3 for the same coordinate conventions.
 * Useful for editor placement: raycast hit point -> { lat, lon } in degrees.
 */
export function vector3ToLatLon(vec3) {
  const v = vec3.clone().normalize();
  const lat = Math.asin(clamp(v.y, -1, 1)); // [-pi/2..pi/2]
  const lon = Math.atan2(v.x, -v.z); // [-pi..pi]
  return {
    lat: THREE.MathUtils.radToDeg(lat),
    lon: THREE.MathUtils.radToDeg(lon)
  };
}

export function createTextureLoader() {
  const loader = new THREE.TextureLoader();
  loader.crossOrigin = 'anonymous';
  return loader;
}

export function isValidUuid(v) {
  // Loose validation; avoids rejecting valid UUIDs from various backends.
  return typeof v === 'string' && /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(v);
}

export function safeJsonParse(s, fallback = null) {
  try {
    return JSON.parse(s);
  } catch {
    return fallback;
  }
}


