/**
 * Ensure Photo Sphere Viewer (v4) assets are present.
 *
 * We intentionally load PSV from CDN at runtime so:
 * - the widget keeps the same camera feel as the editor (PSV inertia)
 * - hotspot coordinates match PSV MarkersPlugin (yaw/pitch degrees)
 *
 * Required globals after load:
 * - window.THREE
 * - window.uEvent
 * - window.PhotoSphereViewer (Viewer + plugins)
 */
let _psvPromise = null;

function loadCssOnce(href, { key }) {
  if (typeof document === 'undefined') return;
  const sel = `link[data-${key}]`;
  if (document.querySelector(sel)) return;
  const link = document.createElement('link');
  link.rel = 'stylesheet';
  link.href = href;
  link.setAttribute(`data-${key}`, 'true');
  document.head.appendChild(link);
}

function loadScriptOnce(src, { key, globalVar } = {}) {
  if (typeof document === 'undefined') return Promise.resolve();
  if (key && document.querySelector(`script[data-${key}]`)) return Promise.resolve();
  if (globalVar && typeof window !== 'undefined' && window[globalVar]) return Promise.resolve();

  return new Promise((resolve, reject) => {
    const s = document.createElement('script');
    s.async = true;
    s.src = src;
    if (key) s.setAttribute(`data-${key}`, 'true');
    s.onload = () => resolve();
    s.onerror = () => reject(new Error(`Panorama360: failed to load script: ${src}`));
    document.head.appendChild(s);
  });
}

export function ensurePsvAssets({
  // user-requested baseline
  psvJs = 'https://cdn.jsdelivr.net/npm/photo-sphere-viewer@4/dist/photo-sphere-viewer.js',
  psvCss = 'https://cdn.jsdelivr.net/npm/photo-sphere-viewer@4/dist/photo-sphere-viewer.min.css',
  // deps required by PSV v4 UMD build
  threeJs = 'https://cdn.jsdelivr.net/npm/three@0.147/build/three.min.js',
  ueventJs = 'https://cdn.jsdelivr.net/npm/uevent@2/browser.min.js',
  // plugins
  markersJs = 'https://cdn.jsdelivr.net/npm/photo-sphere-viewer@4/dist/plugins/markers.min.js',
  markersCss = 'https://cdn.jsdelivr.net/npm/photo-sphere-viewer@4/dist/plugins/markers.min.css',
  gyroscopeJs = 'https://cdn.jsdelivr.net/npm/photo-sphere-viewer@4/dist/plugins/gyroscope.min.js',
  stereoJs = 'https://cdn.jsdelivr.net/npm/photo-sphere-viewer@4/dist/plugins/stereo.min.js'
} = {}) {
  if (_psvPromise) return _psvPromise;

  _psvPromise = (async () => {
    loadCssOnce(psvCss, { key: 'p360-psv-css' });
    loadCssOnce(markersCss, { key: 'p360-psv-markers-css' });

    await loadScriptOnce(threeJs, { key: 'p360-three', globalVar: 'THREE' });
    await loadScriptOnce(ueventJs, { key: 'p360-uevent', globalVar: 'uEvent' });
    await loadScriptOnce(psvJs, { key: 'p360-psv' });
    await loadScriptOnce(markersJs, { key: 'p360-psv-markers' });

    // Optional: gyro + stereo for a "VR-like" mode (mobile headset / cardboard).
    // StereoPlugin requires GyroscopePlugin.
    try {
      await loadScriptOnce(gyroscopeJs, { key: 'p360-psv-gyro' });
      await loadScriptOnce(stereoJs, { key: 'p360-psv-stereo' });
    } catch {
      // Ignore; VR button will be disabled if plugins are missing.
    }

    const PSV = typeof window !== 'undefined' ? window.PhotoSphereViewer : null;
    if (!PSV?.Viewer) throw new Error('Panorama360: Photo Sphere Viewer failed to initialize');
    return PSV;
  })();

  return _psvPromise;
}

